def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    factor = ((ratio - a) ** 6) / (a * b * 0.85 + 1)
                    priority += factor * np.cos(ratio * b / (a + 2))
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 1.7
            if ratio > 10:
                priority += np.log(ratio) * np.sin(ratio) * 3
            else:
                for c in range(5):
                    priority += np.tanh(ratio / (c + 1)) * np.cos(2 * np.pi * c * ratio / 3)
        elif 5 < ratio <= 8:
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * q) / (q + 0.7)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            if bin_cap < item * 1.3:
                priority += np.sqrt(item / (bin_cap + 0.3)) * 2
            else:
                priority -= np.cos(25 * ratio) * 3
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 1.6) * np.sin(r * ratio * 0.9)
                if r % 3 == 0:
                    s -= np.log(r + 1) * 0.2
                else:
                    s += np.exp(-r / (ratio + 0.2)) * 0.1
            priority = (s * np.sin(6 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2
            for d in range(1, 5):
                priority += np.cos(d * ratio * i) * ((ratio - 1.7) ** d) / d
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 0.7) * np.cos(n * ratio * 1.5)
            if bin_cap < item * 1.15:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.sin(30 * ratio) * 3
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 1.1) * ((ratio - 0.9) ** m) / (m + 0.5)
        elif 0.4 <= ratio < 1:
            s = 0
            for w in range(1, 18):
                s += ((1 - ratio) ** w) / (w * 3.8) * np.sin(w * item * 1.3)
                if w % 4 == 0:
                    s += np.log1p(bin_cap + w)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.5) * 0.85
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 15):
                s += ((0.4 - ratio) ** k) / (k * 2.5) * np.sin(k * ratio * 3)
                if k % 2 == 1:
                    s -= np.exp(-k / (ratio + 0.1)) * 0.3
            priority = s + 2 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.4)
        else:
            s = 0
            for t in range(1, 13):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
                if t % 3 == 0:
                    s += np.tanh(item / (t + 0.5))
                else:
                    s -= np.log1p(ratio * t) * 0.2
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.95)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if (i * int(item)) % 7 == 0:
            priority += np.tanh(ratio * i) * 2
        else:
            priority -= np.tanh(ratio / (i + 1)) * 2
        priorities[i] = priority
    return priorities
